import {
  useState,
  HTMLAttributes,
  useEffect,
  useCallback,
} from 'preact/compat';
import { Button, Icon } from '@adobe-commerce/elsie/components';
import { events } from '@adobe-commerce/event-bus';
import { Container } from '@adobe-commerce/elsie/lib';
import { Heart, HeartFilled } from '@adobe-commerce/elsie/icons';
import { state } from '@/wishlist/lib/state';
import { useText } from '@adobe-commerce/elsie/i18n';

import {
  addProductsToWishlist,
  removeProductsFromWishlist,
  config,
} from '@/wishlist/api';
import { Product } from '@/wishlist/data/models';
import { getPersistedWishlistData } from '@/wishlist/lib/persisted-data';
import { VNode } from 'preact';
import { isMatchingWishlistItem } from '@/wishlist/lib/wishlist-item-comparator';

export interface WishlistToggleProps extends HTMLAttributes<HTMLDivElement> {
  product: Product;
  iconWishlisted?: VNode<HTMLAttributes<SVGSVGElement>>;
  iconToWishlist?: VNode<HTMLAttributes<SVGSVGElement>>;
  size?: 'medium' | 'large';
  variant?: 'primary' | 'secondary' | 'tertiary';
  disabled?: boolean;
  labelToWishlist?: string;
  labelWishlisted?: string;
  onClick?: () => void;
  removeProdFromCart?: (
    product: { uid: string; quantity: number }[]
  ) => Promise<any>;
}

export const WishlistToggle: Container<WishlistToggleProps> = ({
  product,
  iconWishlisted,
  iconToWishlist,
  size,
  variant,
  disabled,
  labelToWishlist,
  labelWishlisted,
  onClick,
  removeProdFromCart,
}: WishlistToggleProps) => {
  const [isLoggedIn, setIsLoggedIn] = useState(state.authenticated);
  const [isWishlisted, setIsWishlisted] = useState(false);
  const [wishlistItem, setWishlistItem] = useState(null);
  const { isGuestWishlistEnabled } = config.getConfig();

  const dictionary = useText({
    addToWishlist: 'Wishlist.Wishlist.ariaLabelAddToWishlist',
    removeFromWishlist: 'Wishlist.Wishlist.ariaLabelRemoveFromWishlist',
  });

  const handleWishlistData = useCallback(() => {
    const updatedWishlist = getPersistedWishlistData();
    const item = updatedWishlist?.items?.find((item: any) =>
      isMatchingWishlistItem(item, {
        sku: product.topLevelSku ?? product.sku,
        optionUIDs:
          product.optionUIDs ??
          (product.selectedOptionsUIDs
            ? Object.values(product.selectedOptionsUIDs)
            : undefined) ??
          (product.bundleOptionsUIDs
            ? Object.values(product.bundleOptionsUIDs)
            : undefined),
      })
    );

    setWishlistItem(item ?? null);
    setIsWishlisted(!!item);
  }, [
    product.topLevelSku,
    product.sku,
    product.optionUIDs,
    product.selectedOptionsUIDs,
    product.bundleOptionsUIDs,
  ]);

  useEffect(() => {
    handleWishlistData();
  }, [handleWishlistData]);

  useEffect(() => {
    const handleAuthentication = (authenticated: boolean) =>
      setIsLoggedIn(authenticated);

    const onAuthenticated = events.on('authenticated', handleAuthentication);
    const onWishlistData = events.on('wishlist/data', handleWishlistData);

    return () => {
      onAuthenticated?.off();
      onWishlistData?.off();
    };
  }, [handleWishlistData]);

  const handleClick = async () => {
    if (isWishlisted) {
      try {
        await removeProductsFromWishlist([wishlistItem]);
      } catch (error) {
        events.emit('wishlist/alert', {
          action: 'removeError',
          item: { product },
        });
        return null;
      }

      setIsWishlisted(false);
      events.emit('wishlist/alert', {
        action: 'remove',
        item: { product },
      });
    } else {
      try {
        await addProductsToWishlist([
          {
            sku: product.topLevelSku ?? product.sku,
            quantity: 1,
            optionsUIDs:
              product.optionUIDs ??
              (product.selectedOptionsUIDs
                ? Object.values(product.selectedOptionsUIDs)
                : undefined) ??
              (product.bundleOptionsUIDs
                ? Object.values(product.bundleOptionsUIDs)
                : undefined),
            enteredOptions: product.options?.items
              ? product.options.items
                  .filter((option: any) => option.selected)
                  .map((option: any) => ({
                    uid: option.uid,
                    value: option.value,
                  }))
              : undefined,
          },
        ]);
      } catch (error) {
        events.emit('wishlist/alert', {
          action: 'addError',
          item: { product },
        });
        return null;
      }

      setIsWishlisted(true);
      events.emit('wishlist/alert', {
        action: 'add',
        item: { product },
      });
      if (removeProdFromCart) {
        await removeProdFromCart([
          {
            uid: product.uid,
            quantity: 0,
          },
        ]);
      }
    }
  };

  if (!isLoggedIn && !isGuestWishlistEnabled) {
    return null;
  }

  const ariaLabel: string = isWishlisted
    ? dictionary['removeFromWishlist'].replace('{PRODUCT_NAME}', product?.name)
    : dictionary['addToWishlist'].replace('{PRODUCT_NAME}', product?.name);

  return (
    <Button
      active={isWishlisted}
      aria-label={ariaLabel}
      data-testid="wishlist-toggle"
      size={size ?? 'medium'}
      variant={variant ?? 'tertiary'}
      disabled={disabled}
      icon={<Icon source={iconToWishlist ?? Heart} />}
      activeIcon={<Icon source={iconWishlisted ?? HeartFilled} />}
      onClick={onClick ?? handleClick}
      children={labelToWishlist}
      activeChildren={labelWishlisted}
    />
  );
};
